#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long extra = Y > X ? Y - X : 0;
        printf("%lld\n", extra);
    }
    return 0;
}

